	.TITLE	INTRO;	--------------------------------------;		(C) 1986 - Daniel Roux;	--------------------------------------	.PROC	M680002	.RADIX	10.	.HEX	.REF	SM8	.REF	DRIVERS	.REF	GESMEM	.REF	NTREL 	.REF	FOS	.REF	LIB	.REF	GENCARMAJREV	=	1		; rvisionMINREV	=	0		; version	.REV	MAJREV,MINREV	.CODE	800,11,B'1111,600,2000,300,2000,3,'N,'E,'F,11; Constantes; ----------GCTXF	=	'N		; fonte du texte  NEF11GCTXS	=	'E!2^7		; style/chasse du texteGCTXT	=	11		; taille du texteGCTBF	=	'T!2^7		; fonte du texte-bulle  T(B)14GCTBS	=	2^BGCBOLD	; style/chasse du texte-bulleGCTBT	=	14		; taille du texte-bulleGCICF	=	'I		; fonte des icnes  IIP32GCICS	=	'I		; style/chasse des icnesGCICT	=	32		; taille des icnesGCICX	=	32		; largeur d'une icneGCICY	=	GCICT		; hauteur d'une icneGCICB	=	8		; position ligne de base; Codes des icnes de IIP32; -------------------------ICOVIDE	=	0		; icne videICOSOURIS=	1		; sourisICOMAIN	=	2		; mainICODETRUIT=	16		; quelques icnes de DESSIN :ICODEPLACE=	17		;ICODUPLIQUE=	18		;ICOBLOCNOTES=	19		;ICOZOOM	=	20		;ICOTOURNE=	21		;ICOMIROIR=	22		;ICOCONTOUR=	23		;ICONEGATIF=	24		;; Dfinition de l'entte d'un gnrateur de caractres; ----------------------------------------------------OGCNBR	=	H'00		; total number of recordsOGCFSN	=	H'02		; font set numberOGCFN	=	H'03		; font numberOGCMSB	=	H'04		; matrix size in bytesOGCMHD	=	H'06		; matrix height in dotsOGCMWB	=	H'08		; matrix width in bytesOGCPSI	=	H'09		; point sizeOGCFCA	=	H'0A		; ASCII code of first characterOGCLCA	=	H'0B		; ASCII code of last characterOGCLMA	=	H'0C		; left margin of matrixOGCBLI	=	H'0E		; bottom of matrix to baselineOGCMH1	=	H'10		; max heigth above baselineOGCMH2	=	H'12		; max extension under baselineOGCMWI	=	H'14		; max width (for fixed spacing)OGCISP	=	H'16		; interline space in dotsOGCVSP	=	H'18		; variable spacedOGCDAT	=	H'1A		; date en BCD jjmmyyyyOGCPWI	=	H'1E		; ^widthOGCPH1	=	H'20		; ^h1OGCPH2	=	H'22		; ^h2OGCPMX	=	H'24		; ^matrixOGCIDE	=	H'26		; text identifierOGCTXT	=	H'80		; textOGCWID	=	256		; 128 x widthOGCH1	=	256+128*1	; 128 x h1OGCH2	=	256+128*2	; 128 x h2OGCMAT	=	256+128*3	; 128 x matrix; En-tte d'un fichier "image"; ----------------------------	.LOC	0OIMTYP:	.BLKB	1		; H'01 = indique type imageOIMCOD:	.BLKB	1		; H'00 = indique pas de codageOIMBIP:	.BLKB	1		; H'01 = 1 bit par pointOIMDIR:	.BLKB	1		; H'02 = coord. X-Y comme cranOIMDLX:	.BLKB	2		; largeur image en pointsOIMDLY:	.BLKB	2		; hauteur image en pointsOIMNBB:	.BLKB	4		; nb de byte pour l'image	.BLKB	20		; rserveLGHIMA:; Variables; ---------	.LOC	0OPDDIS:	.BLKB	4		; ^descripteur de la fentreOBUDIS:	.BLKB	100		; buffer pour write displayOBUICO:	.BLKB	GCICY*GCICX/8+4	; buffer pour une icneLGVAR:; Programme; ---------	.LOC	0START:;;?	.W	LIB,?OPELIB	LOAD.W	D3,#2	.W	LIB,?MOUSE	LOAD.L	D4,#LGVAR	LOAD.W	D1,#MTYPCP	.W	GESMEM,?GETMEM	; demande mmoire pour var.	JUMP,NE ERFAT	LOAD.L	A6,A4		; A6 <-- ^variables10$:	CLR.B	(A4+)		; met TOUTES les variables  zro	DEC.L	D4	JUMP,NE 10$	.W	LIB,?GCHDIS	; D6 <-- canal cran	LOAD.W	D3,#TYPWDO	; D3 <-- type fentre cran	LOAD.L	D4,#4		; D4 <-- longueur demande	LOAD.L	A4,#(A6)+OPDDIS	; A4 <-- ^buffer	.W	FOS,?RSTATUS	; demande le ^rel !	JUMP,NE ERFAT	LOAD.L	A0,(A6)+OPDDIS	; A0 <-- ^descripteur de la fentre <<PREMANANT>>	.W	LIB,?AFTIM	.B	LOADGC,GCICF,GCICS,GCICT	.B	0	.EVEN	JUMP,NE ERFAT	.W	LIB,?AFTIM	.B	LOADGC,GCTBF,GCTBS,GCTBT	.B	0	.EVEN	JUMP,NE ERFAT;;?	LOAD.L	A3,#R16"TXIMA1;;?	CALL	AFIMAGE;;?	CALL	WAITKEY;;?	CALL	LABYRINTHE;;?	CALL	VOITURE	CALL	CLIC;;?	CALL	MENU	LOAD.L	A4,A6	LOAD.W	D1,#MTYPCP	.W	GESMEM,?GIVMEMERFAT:;;?	.W	LIB,?CLOLIB;;?	.W	FOS,?STOP	EXIT;;?	.INS	INTROLAB;;?	.INS	INTROVOIT;;?	.INS	INTROCLIC;;?	.INS	INTROMENUPOBCLICX=	118		; bullePOBCLICY=	21LGBCLICX=	283LGBCLICY=	85;--------\\; CLIC    >;========/CLIC:	LOAD.L	A3,#R16"TXIMAS3	CALL	AFIMAGE	JUMP,NE 90$	CLR.B	D0		; D0 <-- carrs cliqus10$:	.W	LIB,?GETCAR	; attend souris ...	COMP.W	D3,#KEYMGR	JUMP,EQ 10$	COMP.W	D3,#KEYMMR	JUMP,EQ 10$	COMP.W	D3,#KEYMDR	JUMP,EQ 10$	COMP.W	D3,#KEYMGP	JUMP',EQ 20$	COMP.W	D3,#KEYMMP	JUMP',EQ 20$	COMP.W	D3,#KEYMDP	JUMP',EQ 20$	CLR.L	D3	.W	LIB,?SETCURS	.W	LIB,?IFMOUSE	LOAD.L	D5,D4	AND.L	D4,#H'FFFF	LOAD.W	D3,#8	CLR.W	D2	.W	LIB,?AFDEC	.W	LIB,?AFSPACE	LOAD.L	D4,D5	CLR.W	D4	SWAP.W	D4	.W	LIB,?AFDEC	.W	LIB,?AFSPACE;;?	LOAD.B	D3,#BIPERR;;?	.W	LIB,?BEEP	JUMP	10$16$:	LOAD.B	D3,#BIPERR	.W	LIB,?BEEP17$:	CALL	ERRCLIC	JUMP	10$20$:	LOAD.L	A3,#R16"ERCLIC1	LOAD.W	D2,D3		; D2 <-- bouton press	.W	LIB,?IFMOUSE	COMP.W	D4,#50	JUMP,LO 16$	COMP.W	D4,#50+20	JUMP,HS 16$	SWAP.W	D4	CLR.B	D1	LOAD.W	D3,#KEYMGP	LOAD.W	D5,#190	COMP.W	D4,#190	JUMP,LO	16$	COMP.W	D4,#190+20	JUMP,LO	30$	INC.B	D1	LOAD.W	D3,#KEYMMP	LOAD.W	D5,#230	COMP.W	D4,#230	JUMP,LO	16$	COMP.W	D4,#230+20	JUMP,LO	30$	INC.B	D1	LOAD.W	D3,#KEYMDP	LOAD.W	D5,#270	COMP.W	D4,#270	JUMP,LO	16$	COMP.W	D4,#270+20	JUMP,HS 16$30$:	LOAD.L	A3,#R16"ERCLIC2	COMP.W	D3,D2		; clic avec le bon bouton ?	JUMP,NE 16$	TSET.L	D0:D1	JUMP,BS 10$	LOAD.W	D3,D5	SWAP.W	D3	LOAD.W	D3,#51	LOAD.W	D2,#INVDOT	LOAD.W	D5,#8+140$:	PUSH.L	D3	LOAD.W	D4,#18	SWAP.W	D4	LOAD.W	D4,#18	.W	LIB,?DRSEG	POP.L	D3	PUSH.L	D3	ADD.W	D3,#17	LOAD.W	D4,#18	SWAP.W	D4	LOAD.W	D4,#-18	.W	LIB,?DRSEG	POP.L	D3	LOAD.W	D4,#4	.W	NTREL,?DELMS	DEC.W	D5	JUMP,NE 40$	LOAD.L	A3,#R16"ERCLIC3	COMP.B	D0,#B'111	JUMP,NE 17$	LOAD.B	D3,#BIPDONE	.W	LIB,?BEEP	LOAD.L	A3,#R16"ERCLIC4	CALL	ERRCLIC	LOAD.W	D4,#50*3	.W	NTREL,?DELMS90$:	RET;-----------\\; ERRCLIC    >;-----------/; Affiche un message dans la bulle.; in	A3.L	^message; out	-; mod	D7.WERRCLIC:	PUSHM.L	D2..D4,A3	LOAD.L	D3,#-1	LOAD.L	D4,D3	.W	LIB,?DRMDEF	LOAD.W	D3,#POBCLICY	SWAP.W	D3	LOAD.W	D3,#POBCLICX	LOAD.W	D4,#LGBCLICY	SWAP.W	D4	LOAD.W	D4,#LGBCLICX	LOAD.W	D2,#SETDOT	.W	LIB,?DRMATRIX	; efface la bulle	.W	LIB,?AFTIM	.B	USEGC,GCTBF,GCTBS,GCTBT	.B	MODCAR	.B	PENDOT!CLRDOT	.B	0	.EVEN	ADD.W	D3,#10	SWAP.W	D3	ADD.W	D3,#16	SWAP.W	D340$:	.W	LIB,?SETCURS	SWAP.W	D3	ADD.W	D3,(A0)+ODFCY	SWAP.W	D3	.W	LIB,?AFTEXT	TEST.B	(A3)	JUMP,NE 40$	.W	LIB,?AFTIM	.B	USEGC,GCTXF,GCTXS,GCTXT	.B	MODCAR	.B	SETDOT	.B	0	.EVEN	POPM.L	D2..D4,A3	RETERCLIC1:	.ASCIZ	" "	.ASCIZ	"    Rat !"	.ASCIZ	"    Visez mieux ..."	.ASCIZ	" "	.B	0ERCLIC2:	.ASCIZ	"Vous n'avez pas utilis"	.ASCIZ	"le bon bouton de la"	.ASCIZ	"souris !"	.ASCIZ	"Recommencez ..."	.B	0ERCLIC3:	.ASCIZ	" Trs bien !"	.ASCIZ	" "	.ASCIZ	" Cliquez encore dans"	.ASCIZ	" les carrs restants ..."	.B	0ERCLIC4:	.ASCIZ	" "	.ASCIZ	"     C'est parfait !"	.B	0	.EVEN;--------\\; AFIMAGE >;========/; Affiche une image dans la fentre.; Si elle est trop petite, elle est centre au milieu de l'cran.; Si elle est trop grande, on affiche sa partie suprieure gauche.; in	A3.L	^nom de l'image; out	D7.W	erreur; mod	D7.WAFIMAGE:	PUSHM.L	D0,D1,D3,D4,D6,A0,A1,A3,A4	.W	LIB,?AFTIM	.B	NOCURS	.B	EOP	.B	0	.EVEN	LOAD.L	D4,#LGHIMA	LOAD.W	D1,#MTYPCP	.W	GESMEM,?GETMEM	; demande un buffer pour l'en-tte	JUMP,NE 90$	LOAD.L	A0,A4		; A0 <-- ^en-tte	LOAD.W	D3,#2^BOPRD	; D3 <-- mode d'ouverture	.W	FOS,?OPEN	; ouvre l'image	JUMP,NE 84$	LOAD.L	A4,A0	.W	FOS,?RDBYTE	; lit l'en-tte	JUMP,NE 82$	COMP.B	(A4)+OIMTYP,#H'82 ; image du LAMI ?	JUMP,NE 20$		; non => 20$				; oui =>	CLR.B	D3	LOAD.L	D4,#256	.W	FOS,?SPOS	; saute la stupide en-tte de 256 bytes !	JUMP,NE 82$	LOAD.L	D4,#LGHIMA	.W	FOS,?RDBYTE	; lit l'en-tte	JUMP,NE 82$20$:	LOAD.W	D0,(A4)+OIMDLX	; D0 <-- largeur de l'image	LOAD.W	D1,(A4)+OIMDLY	; D1 <-- hauteur de l'image	LOAD.W	D4,D0	SR.W	D4,#3	MUL.WU	D4,D1		; D4 <-- largeur*hauteur/8	PUSH.W	D1	LOAD.W	D1,#MTYPCP	.W	GESMEM,?GETMEM	; demande un buffer pour toute l'image	POPM.W	D1	JUMP,NE 82$	LOAD.L	A1,A4		; A1 <-- ^image	.W	FOS,?RDBYTE	; lit toute l'image	JUMP,NE 80$	LOAD.L	A3,A0		; A3 <-- prend buffer en-tte pour STRING	LOAD.W	D3,D0	SR.W	D3,#3	LOAD.W	(A3)+10,D3	; source: <ii>	CLR.W	(A3)+20		; destination: <ii>	.W	LIB,?GETDIM	; D4 <-- dimensions de la fentre	COMP.W	D0,D4		; image trop large ?	JUMP,HI 50$		; oui => 50$	CLR.W	(A3)+2		; source: <xx>	LOAD.W	(A3)+22,D0	; image: <dxx>	SUB.W	D4,D0	SR.W	D4,#1;;?	LOAD.W	(A3)+12,D4	; destination: <xx>	JUMP	55$50$:	CLR.W	(A3)+2		; source: <xx>	CLR.W	(A3)+12		; destination: <xx>	LOAD.W	(A3)+22,D4	; image: <dxx>55$:	SWAP.W	D4	COMP.W	D1,D4		; image trop haute ?	JUMP,HI 60$		; oui => 60$	CLR.W	(A3)+4		; source: <yy>	LOAD.W	(A3)+24,D1	; image: <dyy>	SUB.W	D4,D1	SR.W	D4,#1;;?	LOAD.W	(A3)+14,D4	; destination: <yy>	JUMP	65$60$:	CLR.W	(A3)+4		; source: <yy>	CLR.W	(A3)+14		; destination: <yy>	LOAD.W	(A3)+24,D4	; image: <dyy>65$:	LOAD.W	(A3)+0,#DRAWRASTER	LOAD.L	(A3)+6,A1	; source: <pppp>	CLR.L	(A3)+16		; destination: <pppp>	LOAD.B	(A3)+26,#SETDOT	; image: <mode>	LOAD.W	D3,#1+26	; D3 <-- longueur	.W	LIB,?STRING	; affiche l'image	CLR.W	D7		; D7 <-- ok80$:	PUSH.W	D7	LOAD.L	A4,A1	LOAD.W	D1,#MTYPCP	.W	GESMEM,?GIVMEM	; rend la mmoire de l'image	POP.W	D782$:	PUSH.W	D7	.W	FOS,?CLOSE	; ferme l'image	POP.W	D784$:	PUSH.W	D7	LOAD.L	A4,A0	LOAD.W	D1,#MTYPCP	.W	GESMEM,?GIVMEM	; rend le buffer pour l'en-tete	POP.W	D790$:	POPM.L	D0,D1,D3,D4,D6,A0,A1,A3,A4	TEST.W	D7		; retour EQ/NE	RET;--------\\; WAITKEY >;========/; Attend une touche, mais pas plus de 8 secondes.; in	-; out	-; mod	D7.WWAITKEY:	PUSHM.L	D3,D4,D710$:	.W	LIB,?IFCAR	; vide le FIFO du clavier	JUMP,EQ 10$	LOAD.W	D4,#50*8	.W	NTREL,?SETTIM	.W	LIB,?GETCAR	; attend ...	LOAD.W	D4,#-1	.W	NTREL,?SETTIM	POPM.L	D3,D4,D7	TEST.W	D7		; retour EQ/NE	RET;---------\\; OPEMOUSE >;=========/; Ouvre le lutin pour la souris.; in	D3.W	code de l'icne;	D4.L	position initiale; out	-; mod	D7.WOPEMOUSE:	PUSHM.L	D2..D4,A3,A4	.W	LIB,?AFTIM	.B	USEGC,GCICF,GCICS,GCICT	.B	0	.EVEN	LOAD.L	D2,D4	LOAD.L	A4,(A0)+ODFPGC	; A4 <-- ^gencar des icnes	LOAD.W	D4,(A4)+OGCMSB	MUL.WU	D4,D3	ADD.L	D4,#OGCMAT	ADD.L	A4,D4		; A4 <-- ^bonne matrice	LOAD.L	A3,#(A6)+OBUDIS+1	LOAD.B	(A3)+0,#DRAWOSPRITE	SWAP.W	D2	LOAD.L	(A3)+1,D2	; <xx> et <yy>	LOAD.W	(A3)+5,#GCICX	; <dxx>	LOAD.W	(A3)+7,#GCICY	; <dyy>	LOAD.L	(A3)+9,A4	; <ssss> matrice chair	CLR.L	(A3)+13		; <cccc> matrice fond automatique	CLR.B	(A3)+17		; <n>	LOAD.W	D3,#18	.W	LIB,?STRING	.W	LIB,?AFTIM	.B	USEGC,GCTXF,GCTXS,GCTXT	.B	0	.EVEN	POPM.L	D2..D4,A3,A4	RET;---------\\; MOVMOUSE >;=========/; Dplace le lutin pour la souris.; in	D4.L	position; out	-; mod	D7.WMOVMOUSE:	PUSHM.L	D3,D4,A3	LOAD.L	A3,#(A6)+OBUDIS+1	LOAD.B	(A3)+0,#DRAWMSPRITE	SWAP.W	D4	LOAD.L	(A3)+1,D4	; <xx> et <yy>	CLR.B	(A3)+5		; <n>	LOAD.W	D3,#6	.W	LIB,?STRING	POPM.L	D3,D4,A3	RET;---------\\; CLOMOUSE >;=========/; Ferme le lutin pour la souris.; in	-; out	-; mod	D7.WCLOMOUSE:	PUSHM.L	D3,A3	LOAD.L	A3,#(A6)+OBUDIS+1	LOAD.B	(A3)+0,#DRAWCSPRITE	CLR.B	(A3)+1		; <n>	LOAD.W	D3,#2	.W	LIB,?STRING	POPM.L	D3,A3	RET;---------\\; ICOMOUSE >;=========/; Utilise une icne comme lutin pour la souris.; in	D3.W	code de l'icne; out	-; mod	D7.WICOMOUSE:	PUSHM.L	D2..D4,A3,A4	.W	LIB,?AFTIM	.B	USEGC,GCICF,GCICS,GCICT	.B	0	.EVEN	LOAD.L	A4,#0	TEST.B	D3	JUMP',EQ 40$	LOAD.L	A4,(A0)+ODFPGC	; A4 <-- ^gencar des icnes	LOAD.W	D4,(A4)+OGCMSB	LOAD.W	D2,D4	MUL.WU	D4,D3	ADD.L	D4,#OGCMAT	ADD.L	A4,D4		; A4 <-- ^bonne matrice	LOAD.L	A3,#(A6)+OBUICO	LOAD.B	(A3+),#GCICX	LOAD.B	(A3+),#GCICY30$:	LOAD.B	(A3+),(A4+)	DEC.W	D2	JUMP,NE 30$	LOAD.L	A4,#(A6)+OBUICO40$:	LOAD.L	A3,#(A6)+OBUDIS+1	LOAD.B	(A3)+0,#DRAWPMOUSE	LOAD.L	(A3)+1,A4	; <ssss> matrice chair	CLR.L	(A3)+5		; <cccc> matrice fond automatique	LOAD.W	D3,#9	.W	LIB,?STRING	.W	LIB,?AFTIM	.B	USEGC,GCTXF,GCTXS,GCTXT	.B	0	.EVEN	POPM.L	D2..D4,A3,A4	RET;--------\\; PMOUSE  >;========/; Positionne la souris en (y;x).; in	D4.L	nouvelle position y;x; out	-; mod	D7.WPMOUSE:	PUSHM.L	D3,D4,D6,A4; Calcul la position absolue dans le grand bitmap $DIS_0.	ADD.W	D4,(A0)+ODFX	SWAP.W	D4	ADD.W	D4,(A0)+ODFY	SWAP.W	D4		; D4 <-- position dans $DIS_0 !; Envoie la commande secrte et mystrieuse de positionnement. 	LOAD.L	A4,#(A6)+OBUDIS+1	LOAD.B	(A4)+0,#'P	; <P>	LOAD.L	(A4)+1,D4	; <yy> <xx>	CLR.B	(A4)+5	LOAD.W	D3,#TYPIO	; D3 <-- type du driver souris	.W	LIB,?GCHMOU	; D6 <-- canal souris	.W	FOS,?COMMAND	POPM.L	D3,D4,D6,A4	RETTXIMA1:	.ASCIZ	"intro1.image"TXIMAS1:.ASCIZ	"intros1.image"TXIMAS2:.ASCIZ	"intros2.image"TXIMAS3:.ASCIZ	"intros3.image"TXIMAS4:.ASCIZ	"intros4.image"	.EVEN	.END	START